final_template:
AWSTemplateFormatVersion: '2010-09-09'
Description: CloudFormation template to create a CloudWatch Dashboard with CloudWatch Logs Insights widgets for VPC flow logs analysis focused on NAT Gateway traffic.

Parameters:
  DashboardName:
    Type: String
    Description: Name for the CloudWatch Dashboard. Used for identification and cost allocation tagging.
    Default: NATGatewayFlowLogsDashboard
  LogGroupName:
    Type: String
    Description: Name of the CloudWatch Logs Log Group where VPC flow logs are stored.
    Default: /aws/vpc/natgateway

Resources:
  # CloudWatch Logs Log Group for VPC Flow Logs with encryption and retention
  VpcFlowLogsLogGroup:
    Type: AWS::Logs::LogGroup
    Properties:
      LogGroupName: !Ref LogGroupName
      RetentionInDays: 30
      KmsKeyId: !Sub arn:aws:kms:${AWS::Region}:${AWS::AccountId}:key/aws-service-key/cloudwatch-logs.amazonaws.com

  # CloudWatch Dashboard with four Logs Insights widgets
  NatGatewayDashboard:
    Type: AWS::CloudWatch::Dashboard
    Properties:
      DashboardName: !Ref DashboardName
      DashboardBody: !Sub |
        {
          "widgets": [
            {
              "type": "loginsights",
              "x": 0,
              "y": 0,
              "width": 24,
              "height": 9,
              "properties": {
                "title": "Top Source IPs by Outbound Traffic (Bytes)",
                "view": "timeSeries",
                "stacked": false,
                "region": "${AWS::Region}",
                "insightQueries": [
                  {
                    "queryMode": "Logs",
                    "queryString": "fields @timestamp, @message\n| filter interfaceId like /eni-/\n| stats sum(bytes) as totalBytes by srcAddr\n| sort totalBytes desc\n| limit 20",
                    "region": "${AWS::Region}",
                    "id": "q1"
                  }
                ],
                "timeRange": {
                  "relative": "24h"
                },
                "autoUpdate": true,
                "legend": {
                  "show": true
                }
              }
            },
            {
              "type": "loginsights",
              "x": 0,
              "y": 9,
              "width": 24,
              "height": 9,
              "properties": {
                "title": "Rejected Connections by Source IP",
                "view": "timeSeries",
                "stacked": false,
                "region": "${AWS::Region}",
                "insightQueries": [
                  {
                    "queryMode": "Logs",
                    "queryString": "fields @timestamp, @message\n| filter interfaceId like /eni-/ and action = \"REJECT\"\n| stats count() as rejectedCount by srcAddr\n| sort rejectedCount desc\n| limit 20",
                    "region": "${AWS::Region}",
                    "id": "q2"
                  }
                ],
                "timeRange": {
                  "relative": "24h"
                },
                "autoUpdate": true,
                "legend": {
                  "show": true
                }
              }
            },
            {
              "type": "loginsights",
              "x": 0,
              "y": 18,
              "width": 24,
              "height": 9,
              "properties": {
                "title": "Top Destination IPs by Inbound Traffic",
                "view": "timeSeries",
                "stacked": false,
                "region": "${AWS::Region}",
                "insightQueries": [
                  {
                    "queryMode": "Logs",
                    "queryString": "fields @timestamp, @message\n| filter interfaceId like /eni-/\n| stats sum(bytes) as totalBytes by dstAddr\n| sort totalBytes desc\n| limit 20",
                    "region": "${AWS::Region}",
                    "id": "q3"
                  }
                ],
                "timeRange": {
                  "relative": "24h"
                },
                "autoUpdate": true,
                "legend": {
                  "show": true
                }
              }
            },
            {
              "type": "loginsights",
              "x": 0,
              "y": 27,
              "width": 24,
              "height": 9,
              "properties": {
                "title": "Total Traffic Volume Over Time (Bytes)",
                "view": "timeSeries",
                "stacked": false,
                "region": "${AWS::Region}",
                "insightQueries": [
                  {
                    "queryMode": "Logs",
                    "queryString": "fields @timestamp, @message\n| filter interfaceId like /eni-/\n| stats sum(bytes) as totalBytes by bin(1h)\n| sort @timestamp asc",
                    "region": "${AWS::Region}",
                    "id": "q4"
                  }
                ],
                "timeRange": {
                  "relative": "24h"
                },
                "autoUpdate": true,
                "legend": {
                  "show": true
                }
              }
            }
          ]
        }

Outputs:
  DashboardURL:
    Description: URL of the CloudWatch Dashboard
    Value: !Sub "https://${AWS::Region}.console.aws.amazon.com/cloudwatch/home?region=${AWS::Region}#dashboards:name=${DashboardName}"

